function limparMensagem(texto) {
  if (typeof texto !== 'string') {
    return '';
  }

  // Remove metadados e dados técnicos
  let resultado = texto
    .replace(/"response_metadata"\s*:\s*{[^}]*}/g, '')
    .replace(/"additional_kwargs"\s*:\s*{[^}]*}/g, '')
    .replace(/"tool_calls"\s*:\s*\[\s*\]/g, '')
    .replace(/"invalid_tool_calls"\s*:\s*\[\s*\]/g, '')
    .replace(/"type"\s*:\s*"(ai|human)"/g, '')
    .replace(/"data"\s*:\s*{[^}]*}/g, '')
    .replace(/,\s*{[^}]*}/g, '')
    .replace(/,\s*\[\s*\]/g, '')
    .replace(/\s*:\s*null/g, '')
    .replace(/\s*:\s*\[\]/g, '')
    .replace(/\s*:\s*{}/g, '')
    .replace(/\\\\[rnt]/g, ' ')
    .replace(/\\\\\"/g, '')
    .replace(/\\\\\\\\/g, '')
    .replace(/[\x00-\x1F\x7F-\x9F]/g, '')
    .replace(/\"+/g, '')
    .replace(/[{}[\]]/g, '')
    .replace(/\s+/g, ' ')
    .trim();

  return resultado;
}

// Processa as mensagens preservando TODA a estrutura original
const items = $input.all();

const processedItems = items.map(item => {
  try {
    // Cria uma cópia completa do item para não modificar o original
    const processedItem = JSON.parse(JSON.stringify(item));

    // Só processa se existir o campo mensagem
    if (processedItem?.json?.mensagem) {
      let mensagem = processedItem.json.mensagem;

      // Se for objeto, converte para string
      if (typeof mensagem === 'object') {
        mensagem = JSON.stringify(mensagem);
      }

      // Limpa apenas o conteúdo da mensagem
      const mensagemLimpa = limparMensagem(mensagem);

      // Só atualiza se houver conteúdo válido
      if (mensagemLimpa && mensagemLimpa.length > 0) {
        processedItem.json.mensagem = mensagemLimpa;
      }
    }

    // Retorna o item com TODA a estrutura original preservada
    return processedItem;

  } catch (error) {
    console.error('Erro ao processar item:', error);
    // Em caso de erro, retorna o item original sem modificações
    return item;
  }
});

return processedItems;

// ===================================================================
// NODE CODE - DETECTAR IA PARA SISTEMA CLAUWAN
// ===================================================================
// OBJETIVO: Detectar conversas com outras IAs para economizar tokens
// ENTRADA: Mensagem do usuário + histórico opcional
// SAÍDA: Pontuação de 0-100 (quanto maior, mais provável ser IA)
// ===================================================================

// Receber dados do N8N (detecta ambiente teste ou produção)
const ambiente = $input.all().length > 0 && $input.all()[0].json.chatInput ? 'teste' : 'producao';

let mensagem = '';
let historico = [];

if (ambiente === 'teste') {
  mensagem = $input.all()[0].json.chatInput || '';
} else {
  // Produção: extrair do body.data.message.conversation
  mensagem = $input.all()[0].json.body?.data?.message?.conversation || '';
  historico = $input.all()[0].json.body?.data?.history || [];
}

mensagem = mensagem.toLowerCase();

// ===================================================================
// CONFIGURAÇÃO DE THRESHOLDS (AJUSTÁVEIS)
// ===================================================================
const config = {
  THRESHOLD_PARAR: 50,      // abaixei para pegar mais casos suspeitos (ajuste conforme)
  THRESHOLD_SUSPEITO: 30,   
  THRESHOLD_HUMANO: 15,     

  // Pesos dos fatores (total deve somar ~100)
  PESO_TRIGGERS_CRITICOS: 60,    // Triggers óbvios de sistema
  PESO_PADRAO_LINGUAGEM: 25,     // Padrões de IA conversacional  
  PESO_COMPORTAMENTO: 10,        // Velocidade, estrutura
  PESO_HISTORICO: 5              // Análise temporal
};

// ===================================================================
// FUNÇÃO PRINCIPAL DE DETECÇÃO
// ===================================================================
function detectarIA(msg, hist) {
  let pontuacao = 0;
  let detalhes = [];
  let nivel = 0;

  // ================================================================
  // NÍVEL 1: TRIGGERS CRÍTICOS (PARADA IMEDIATA)
  // ================================================================
  const triggersCriticos = [
    // Menus textuais
    { regex: /escolha uma das seguintes opções/i, pontos: 90, desc: "Menu texto 'Escolha uma das seguintes opções'" },
    { regex: /^\d+\s*[-.)]/m, pontos: 85, desc: "Lista numerada no início da linha" },

    // Sistemas de atendimento
    { regex: /bem.?vind[oa].*atendimento/i, pontos: 95, desc: "Sistema de atendimento" },
    { regex: /horário.*(funcionamento|atendimento)/i, pontos: 90, desc: "Horário funcionamento/atendimento" },
    { regex: /digite.*\d+.*para/i, pontos: 95, desc: "Menu numérico" },
    { regex: /pressione.*\d+/i, pontos: 90, desc: "Pressione número" },
    { regex: /agradecimento.*\d+/i, pontos: 90, desc: "Agradecimento com número" },
    { regex: /agradece seu contato/i, pontos: 95, desc: "Agradecimento (ajustado)" },

    // Chatbots/Assistentes  
    { regex: /sou.*assistente.*virtual/i, pontos: 95, desc: "Assistente virtual" },
    { regex: /sou.*chatbot/i, pontos: 95, desc: "Chatbot declarado" },
    { regex: /sistema.*automatizado/i, pontos: 85, desc: "Sistema automatizado" },
    { regex: /bot.*atendimento/i, pontos: 90, desc: "Bot de atendimento" },

    // Frases típicas de bots
    { regex: /como.*posso.*auxiliar/i, pontos: 70, desc: "Como posso auxiliar" },
    { regex: /como.*(posso|podemos|poderia|poderemos).*ajud/i, pontos: 70, desc: "Frase de oferta de ajuda" },
    { regex: /em.*que.*posso.*ajud/i, pontos: 65, desc: "Em que posso ajudar" },
    { regex: /qual.*motivo.*contato/i, pontos: 75, desc: "Motivo do contato" },
    { regex: /selecione.*opção/i, pontos: 80, desc: "Selecione opção" },

    // Fora de horário
    { regex: /fora.*horário.*atendimento/i, pontos: 85, desc: "Fora de horário" },
    { regex: /retornaremos.*contato/i, pontos: 80, desc: "Retornaremos contato" },
    { regex: /deixe.*sua.*mensagem/i, pontos: 75, desc: "Deixe mensagem" },
    { regex: /atendimento.*encerrado/i, pontos: 85, desc: "Atendimento encerrado" },

    // URLs na mensagem (muito comum em bots)
    { regex: /https?:\/\/\S+/i, pontos: 70, desc: "URL na mensagem" }
  ];

  // Verificar triggers críticos
  let maxPontosCriticos = 0;
  for (const trigger of triggersCriticos) {
    if (trigger.regex.test(msg)) {
      maxPontosCriticos = Math.max(maxPontosCriticos, trigger.pontos);
      detalhes.push(`CRÍTICO: ${trigger.desc} (+${trigger.pontos})`);
      if (trigger.pontos >= 85) nivel = 1; // Nível crítico
    }
  }
  pontuacao += Math.min(maxPontosCriticos * (config.PESO_TRIGGERS_CRITICOS / 100), 60);

  // ================================================================
  // NÍVEL 2: PADRÕES DE LINGUAGEM IA
  // ================================================================
  const padroesIA = [
    // Linguagem excessivamente formal
    { regex: /certamente.*posso/i, pontos: 15, desc: "Certamente posso" },
    { regex: /fico.*feliz.*ajudar/i, pontos: 15, desc: "Fico feliz em ajudar" },
    { regex: /será.*prazer/i, pontos: 12, desc: "Será um prazer" },
    { regex: /permita.*me.*esclarecer/i, pontos: 18, desc: "Permita-me esclarecer" },
    { regex: /gostaria.*informar/i, pontos: 15, desc: "Gostaria de informar" },
    { regex: /é.*importante.*mencionar/i, pontos: 20, desc: "É importante mencionar" },
    { regex: /vale.*ressaltar/i, pontos: 18, desc: "Vale ressaltar" },
    { regex: /cabe.*destacar/i, pontos: 18, desc: "Cabe destacar" },

    // Padrões específicos de IA
    { regex: /baseado.*minha.*experiência/i, pontos: 20, desc: "Baseado na experiência" },
    { regex: /como.*um.*\w+.*posso.*dizer/i, pontos: 25, desc: "Como um X posso dizer" },
    { regex: /é.*uma.*excelente.*pergunta/i, pontos: 15, desc: "Excelente pergunta" },
    { regex: /vou.*explicar.*forma.*didática/i, pontos: 20, desc: "Forma didática" },
    { regex: /posso.*ajudar.*mais.*alguma.*coisa/i, pontos: 12, desc: "Mais alguma coisa" }
  ];

  let pontosPadrao = 0;
  for (const padrao of padroesIA) {
    if (padrao.regex.test(msg)) {
      pontosPadrao += padrao.pontos;
      detalhes.push(`PADRÃO: ${padrao.desc} (+${padrao.pontos})`);
    }
  }
  pontuacao += Math.min(pontosPadrao * (config.PESO_PADRAO_LINGUAGEM / 100), 25);
  if (pontosPadrao >= 40) nivel = Math.max(nivel, 2);

  // ================================================================
  // NÍVEL 3: ANÁLISE COMPORTAMENTAL
  // ================================================================
  let pontosComportamento = 0;

  // Estrutura muito formal
  if (msg.includes('•') || msg.includes('✓') || msg.includes('→')) {
    pontosComportamento += 15;
    detalhes.push('ESTRUTURA: Bullet points (+15)');
  }

  // Mensagem muito longa e estruturada
  if (msg.length > 500 && msg.split('\n').length > 5) {
    pontosComportamento += 12;
    detalhes.push('ESTRUTURA: Muito longa e estruturada (+12)');
  }

  // Muito educado (múltiplas cortesias)
  const cortesias = ['obrigado', 'por favor', 'desculpe', 'agradeço'];
  let contadorCortesia = 0;
  cortesias.forEach(cortesia => {
    if (msg.includes(cortesia)) contadorCortesia++;
  });
  if (contadorCortesia >= 3) {
    pontosComportamento += 10;
    detalhes.push('COMPORTAMENTO: Muito educado (+10)');
  }

  // Listas numeradas desnecessárias
  if (/\d+[\.\)].{10,}/g.test(msg)) {
    pontosComportamento += 8;
    detalhes.push('ESTRUTURA: Listas numeradas (+8)');
  }

  pontuacao += Math.min(pontosComportamento * (config.PESO_COMPORTAMENTO / 100), 10);
  if (pontosComportamento >= 30) nivel = Math.max(nivel, 2);

  // ================================================================
  // NÍVEL 4: ANÁLISE DE HISTÓRICO (SE DISPONÍVEL)
  // ================================================================
  let pontosHistorico = 0;

  if (hist && hist.length > 1) {
    const agora = new Date();
    const mensagensRecentes = hist.filter(h => {
      const tempo = new Date(h.timestamp || agora);
      return (agora - tempo) < 300000; // 5 minutos
    });

    if (mensagensRecentes.length >= 3) {
      pontosHistorico += 8;
      detalhes.push('HISTÓRICO: Respostas muito rápidas (+8)');
    }

    if (hist.length >= 5) {
      const horarios = hist.map(h => new Date(h.timestamp || agora).getHours());
      const variacaoHorario = Math.max(...horarios) - Math.min(...horarios);
      if (variacaoHorario <= 2) {
        pontosHistorico += 6;
        detalhes.push('HISTÓRICO: Sempre disponível (+6)');
      }
    }
  }

  pontuacao += Math.min(pontosHistorico * (config.PESO_HISTORICO / 100), 5);

  // ================================================================
  // FATORES DE REDUÇÃO (INDICADORES HUMANOS)
  // ================================================================
  let reducao = 0;

  if (/\b(vc|pq|tbm|q|oq|fds)\b/i.test(msg)) {
    reducao += 15;
    detalhes.push('HUMANO: Abreviações naturais (-15)');
  }

  const girias = ['cara', 'mano', 'galera', 'show', 'massa', 'top', 'valeu', 'blz'];
  let contadorGirias = 0;
  girias.forEach(giria => {
    if (msg.includes(giria)) contadorGirias++;
  });
  if (contadorGirias >= 1) {
    reducao += contadorGirias * 8;
    detalhes.push(`HUMANO: Gírias (${contadorGirias}x) (-${contadorGirias * 8})`);
  }

  const emojisNaturais = ['😂', '🤣', '😅', '😊', '🙄', '😤', '👍', '👎', '❤️'];
  let contadorEmojis = 0;
  emojisNaturais.forEach(emoji => {
    if (msg.includes(emoji)) contadorEmojis++;
  });
  if (contadorEmojis >= 1) {
    reducao += contadorEmojis * 5;
    detalhes.push(`HUMANO: Emojis naturais (-${contadorEmojis * 5})`);
  }

  if (/urgent[ei]|rápido|já|agora|hoje/i.test(msg)) {
    reducao += 10;
    detalhes.push('HUMANO: Urgência (-10)');
  }

  pontuacao = Math.max(0, pontuacao - reducao);

  // ================================================================
  // DETERMINAÇÃO FINAL DO NÍVEL
  // ================================================================
  if (pontuacao >= config.THRESHOLD_PARAR) {
    nivel = Math.max(nivel, 1);
  } else if (pontuacao >= config.THRESHOLD_SUSPEITO) {
    nivel = Math.max(nivel, 2);
  } else if (pontuacao >= config.THRESHOLD_HUMANO) {
    nivel = Math.max(nivel, 3);
  }

  return {
    pontuacao: Math.round(pontuacao),
    nivel: nivel,
    acao: pontuacao >= config.THRESHOLD_PARAR ? 'PARAR' : 'CONTINUAR',
    confianca: pontuacao >= config.THRESHOLD_PARAR ? 'ALTA' : 
               pontuacao >= config.THRESHOLD_SUSPEITO ? 'MÉDIA' : 'BAIXA',
    detalhes: detalhes,
    config: config,
    timestamp: new Date().toISOString()
  };
}

// ===================================================================
// EXECUÇÃO E RETORNO DOS DADOS
// ===================================================================
const resultado = detectarIA(mensagem, historico);

// Debug log (pode remover depois)
console.log('=== DETECÇÃO DE IA ===');
console.log(`Ambiente: ${ambiente}`);
console.log(`Mensagem: "${mensagem.substring(0, 100)}..."`);
console.log(`Pontuação: ${resultado.pontuacao}/100`);
console.log(`Nível: ${resultado.nivel}`);
console.log(`Ação: ${resultado.acao}`);
console.log(`Detalhes: ${resultado.detalhes.join(' | ')}`);
console.log('=====================');

// Retorno para o N8N (sempre retornar array com pelo menos um objeto)
return [
  {
    json: {
      ambiente,
      mensagem,
      ia_detection: {
        is_ia: resultado.pontuacao >= config.THRESHOLD_PARAR,
        pontuacao: resultado.pontuacao,
        nivel: resultado.nivel,
        acao: resultado.acao,
        confianca: resultado.confianca,
        detalhes: resultado.detalhes,
        should_stop: resultado.pontuacao >= config.THRESHOLD_PARAR,
        timestamp: resultado.timestamp
      },
      parar_conversa: resultado.pontuacao >= config.THRESHOLD_PARAR,
      debug_log: {
        user: $input.all()[0]?.json.body?.data?.key?.remoteJid || 'unknown',
        message_preview: mensagem.substring(0, 100),
        detection_result: resultado,
        config_used: config
      }
    }
  }
];
